ENTRY.C_EXCHGE_RATE2:
var ccy1 = DV.getCurrentDoData("CPYT_CR_CCY");
  DV.writeLog("CPYT_CR_CCY"+ccy1);
    var baseCCY =DV.SYS_LCY ;
   DV.writeLog("baseCCY DR"+baseCCY);
    var defaultRate = '1';
  DV.writeLog("defaultRate DR"+defaultRate);
    var cnty = DV.getCountryCode();
  DV.writeLog("cnty DR"+cnty);
    if(ccy1!= null){
  DV.writeLog("1 DR");
      if(ccy1 != baseCCY){
  DV.writeLog("2 DR");
    	sql = "C_FROM_CCY = '"+ ccy1 +"' AND C_TO_CCY='"+baseCCY+"' and C_BK_GROUP_ID='STBANK' and C_CNTY_CODE='"+cnty+"' and C_DESC_ID='TT Buying' ";
    	DV.SYS_getTableData('F_VALUE','EXIMSYS.STD_EXCHAN_RATE',sql);
      }else{
  DV.writeLog("3 DR");
    	DV.appendField(defaultRate);
      }
    }else{
  DV.writeLog("4 DR");
    	DV.appendField(defaultRate);
    }
